import"./DsnmJJEf.js";import"./69_IOA4Y.js";import{n as s,b as l,d as r}from"./B62klROV.js";import{l as d,s as u}from"./BUr6unyB.js";import{C as p}from"./DqIch5ks.js";const e={title:"the evil has been defeated",date:"Feb 26, 2023",banner:{file:"happymeowth.webp",alt:"meowth jumping up into the sky very excitedly"}},{title:g,date:w,banner:k}=e;var c=r(`<p>hey, ever wanted to download a youtube video without a hassle? cobalt is here to help. this update fixes all issues related to youtube downloads.
not only that, but it also introduces features never before seen in a downloader, such as youtube dub downloads! read below to see what’s up :)</p> <span class="text-backdrop">tl;dr:</span> <ul><li>audio in youtube videos FINALLY no longer gets cut off.</li> <li>you now can pick any video resolution you want (from 360p to 8k) and any possible youtube video codec (h264/av1/vp9).</li> <li>you now can download youtube videos with dubs in your native language. just check settings > audio.</li> <li>youtube processing has been vastly sped up.</li></ul> <p>ok, now onto the nerdy part of changelog. this update is pretty huge and includes improvements across the board.</p> <p>service improvements:</p> <ul><li>all youtube functionality has been reworked. cobalt now relies on innertube apis, not web scraping.</li> <li>random audio cut off issue has been fixed, let me know if it ever occurs again. (closes #62, #66, #75, #88).</li> <li>added support for youtube dubs. currently it’s using your browser’s default language when enabled, but i have plans on making a picker. i’ll ask people on twitter and mastodon if this feature is needed, and add a picker in next updates.</li> <li>instead of adding more quality presets, i added granular quality options. pick whatever you like, from 360p up to 4320p (for all services, not just youtube).</li> <li>replaced a format picker with codec picker for youtube. you can pick h264, av1, or vp9. all of them should work as expected (closes #88).</li> <li>youtube audio files are now properly matched to corresponding video files.</li> <li>it’s now always possible to download pristine h264 720p/360p videos from youtube. these videos will work ANYWHERE, so they’re default for mobile.</li> <li>youtube requests are no longer permanently cached, ram usage should drop even further.</li> <li>youtube video and audio file names now include codec and dub language when applicable.</li> <li>max video and audio duration limits have been bumped up to 3 hours.</li> <li>general performance of entire youtube download process has been greatly improved.</li> <li>vk module has been reworked to be more compact and not make use of outdated technique of quality picking. should also be way more reliable.</li></ul> <p>internal improvements:</p> <ul><li>cleaned up services config, all constants have been moved directly to modules for quicker access.</li> <li>matching module has been slightly cleaned up.</li></ul> <p>interface improvements:</p> <ul><li>many descriptions and error messages have been slightly tuned to be less wordy.</li> <li>unnecessary title duplications in settings have been merged into one.</li> <li>added more clarity to quality and codec descriptions.</li></ul> <p>if you use cobalt api, please note that you have to update your creation to support new features.</p> <p>this is the second batch of 5.x improvements, there’s way more to come. thank you for being here, i really appreciate your support.</p> <p>if you want to thank me (the developer), there’s a nice tab under this changelog that has “donations” text on it. anything helps me continue developing and hosting the friendliest media downloader :D</p>`,1);function $(o,t){const a=d(t,["children","$$slots","$$events","$$legacy"]);p(o,u(()=>a,()=>e,{children:(i,h)=>{var n=c();s(24),l(i,n)},$$slots:{default:!0}}))}export{$ as default,e as metadata};
